import type { ChannelPlugin } from "openclaw/plugin-sdk/core";
import type { PulseBoardAccount } from "./types.js";

// getChatChannelMeta("pulseboard") is the production call once "pulseboard" is
// registered in src/channels/ids.ts CHAT_CHANNEL_ORDER. Until then the meta is
// built inline with the same shape that getChatChannelMeta would return.
const meta: ReturnType<typeof getChatChannelMeta> = {
  id: "pulseboard",
  label: "PulseBoard",
  selectionLabel: "PulseBoard (Bulletin)",
  docsPath: "/channels/pulseboard",
  blurb: "Connect to PulseBoard bulletin messaging.",
};

export const pulseBoardPlugin: ChannelPlugin<PulseBoardAccount> = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta,
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    config: {
      listAccountIds: (_cfg) => [],
      defaultAccountId: (_cfg) => "default",
      resolveAccount: (_cfg, _accountId) => ({
        boardUrl: "",
        apiToken: "",
        username: "",
      }),
      isConfigured: (_account) => false,
      describeAccount: (_account) => ({ accountId: "default", configured: false }),
    },
    setup: {
      applyAccountConfig: async (_params) => {
        // stub: no-op for scaffolding
      },
    },
    messaging: {
      normalizeTarget: (target) => target.trim(),
    },
    gateway: {
      startAccount: async (ctx) => {
        ctx.log?.info(
          `[pulseboard] connecting account "${ctx.accountId}" — stub implementation`,
        );
      },
    },
  },
  outbound: {
    base: {
      deliveryMode: "direct",
      textChunkLimit: 4000,
    },
    attachedResults: {
      channel: "pulseboard",
      sendText: async ({ to, accountId }) => {
        // stub: real implementation would POST to the PulseBoard API
        const messageId = `pb-${Date.now()}`;
        return { channel: "pulseboard", to, messageId, accountId };
      },
    },
  },
});

